mapper.select:
SELECT o.id, o.user_id AS userId, o.dept_id AS deptId, o.overtime_type AS overtimeType, CASE o.overtime_type WHEN 'WORKDAY' THEN '工作日加班' WHEN 'REST_DAY' THEN '休息日加班' WHEN 'HOLIDAY' THEN '节假日加班' END AS overtimeTypeName, o.start_time AS startTime, o.end_time AS endTime, o.hours, o.reason, o.status, CASE o.status WHEN 'PENDING' THEN '待审批' WHEN 'APPROVED' THEN '已通过' WHEN 'REJECTED' THEN '已拒绝' WHEN 'CANCELLED' THEN '已撤回' WHEN 'COMPLETED' THEN '已完成' END AS statusName, o.compensation_type AS compensationType, CASE o.compensation_type WHEN 'BREAK' THEN '调休' WHEN 'SALARY' THEN '加班费' END AS compensationTypeName, o.approver_id AS approverId, o.approved_time AS approvedTime, o.current_approver_id AS currentApproverId, o.create_time AS createTime FROM oa_overtime o
AND o.user_id = #{userId}
AND o.status = #{status}
AND o.overtime_type = #{overtimeType}
AND o.start_time >= #{startDate}
AND o.end_time <= #{endDate}
ORDER BY o.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM oa_overtime o


        AND o.user_id = #{userId}


        AND o.status = #{status}


        AND o.overtime_type = #{overtimeType}


        AND o.start_time >= #{startDate}


        AND o.end_time <= #{endDate}

SELECT * FROM oa_overtime_break
WHERE user_id = #{userId}
ORDER BY create_time DESC

SELECT * FROM oa_overtime_break
WHERE user_id = #{userId}
AND expired_time > #{now}
ORDER BY create_time DESC

SELECT COALESCE(SUM(available_hours), 0)
FROM oa_overtime_break
WHERE user_id = #{userId}
AND expired_time > #{now}
